import json

def execute(inputs):
    """Run basic smoke test: import the module and check public API."""
    module_code = inputs.get('module_code', '')
    toolkit_spec = inputs.get('toolkit_spec', {})
    if isinstance(toolkit_spec, str):
        toolkit_spec = json.loads(toolkit_spec)
    valid = inputs.get('valid', True)

    if not valid:
        return {
            'test_passed': False,
            'module_code': module_code,
            'toolkit_spec': toolkit_spec,
            'test_output': 'Skipped: module failed validation'
        }

    # Try to compile and exec the module
    test_log = []
    try:
        code_obj = compile(module_code, '<toolkit_module>', 'exec')
        namespace = {}
        exec(code_obj, namespace)
        test_log.append('Module loaded successfully')

        # Check that public API items exist in namespace
        public_api = toolkit_spec.get('public_api', [])
        for api_item in public_api:
            api_name = api_item.get('name', '')
            top_name = api_name.split('.')[0]
            if top_name in namespace:
                test_log.append(f'Found: {top_name}')
            else:
                test_log.append(f'Missing: {top_name}')

        return {
            'test_passed': True,
            'module_code': module_code,
            'toolkit_spec': toolkit_spec,
            'test_output': '\n'.join(test_log)
        }
    except Exception as e:
        return {
            'test_passed': False,
            'module_code': module_code,
            'toolkit_spec': toolkit_spec,
            'test_output': f'Smoke test failed: {e}'
        }

outputs = execute(inputs)

